+#[derive(Debug, Clone, Copy, PartialEq, Eq)]
+enum PerlShellCall {
+    System,
+    Exec,
+    Backticks,
+    Qx,
+}
+
+impl PerlShellCall {
+    #[must_use]
+    const fn id_prefix(self) -> &'static str {
+        match self {
+            Self::System => "system",
+            Self::Exec => "exec",
+            Self::Backticks => "backticks",
+            Self::Qx => "qx",
+        }
+    }
+}
+
+#[derive(Clone, Copy)]
+enum PerlCommentState {
+    Normal,
+    Single,
+    Double,
+    Backtick,
+}
